// ═══════════════════════════════════════════
// 060 — STEP 1: VALIDAR ESTRUTURA DO PAYLOAD
// ═══════════════════════════════════════════

const body = $input.item.json.body || $input.item.json;
const erros = [];

// Blocos obrigatórios
if (!body.lead || typeof body.lead !== 'object') erros.push('Bloco lead ausente');
if (!body.localizacao || typeof body.localizacao !== 'object') erros.push('Bloco localizacao ausente');
if (!body.demanda || typeof body.demanda !== 'object') erros.push('Bloco demanda ausente');
if (!body.consentimento || typeof body.consentimento !== 'object') erros.push('Bloco consentimento ausente');

if (erros.length > 0) {
  return [{
    json: {
      ok: false,
      erro: 'Payload inválido: ' + erros.join('; '),
      _abort: true
    }
  }];
}

// Campos obrigatórios dentro dos blocos
const lead = body.lead;
const loc = body.localizacao;
const dem = body.demanda;
const cons = body.consentimento;

const camposFaltantes = [];
if (!lead.nome) camposFaltantes.push('lead.nome');
if (!lead.whatsapp) camposFaltantes.push('lead.whatsapp');
if (!lead.email) camposFaltantes.push('lead.email');
if (!lead.tipo_cliente) camposFaltantes.push('lead.tipo_cliente');
if (!lead.nome_empresa_ou_condominio) camposFaltantes.push('lead.nome_empresa_ou_condominio');
if (!loc.bairro) camposFaltantes.push('localizacao.bairro');
if (!loc.cidade) camposFaltantes.push('localizacao.cidade');
if (!loc.endereco_completo) camposFaltantes.push('localizacao.endereco_completo');
if (!dem.servico_interesse) camposFaltantes.push('demanda.servico_interesse');
if (!dem.urgencia) camposFaltantes.push('demanda.urgencia');
if (!dem.descricao) camposFaltantes.push('demanda.descricao');

if (camposFaltantes.length > 0) {
  return [{
    json: {
      ok: false,
      erro: 'Campos obrigatórios faltando: ' + camposFaltantes.join(', '),
      _abort: true
    }
  }];
}

// Passar payload validado
return [{
  json: {
    _abort: false,
    lead: body.lead,
    localizacao: body.localizacao,
    infraestrutura: body.infraestrutura || {},
    demanda: body.demanda,
    midia: body.midia || {},
    consentimento: body.consentimento,
    origem_lead: body.origem_lead || { canal: 'site', versao_form: 'V2', pagina: 'desconhecida' }
  }
}];

// ═══════════════════════════════════════════
// 060 — STEP 2: NORMALIZAR DADOS
// ═══════════════════════════════════════════

const d = $input.item.json;
const lead = d.lead;
const loc = d.localizacao;
const infra = d.infraestrutura;
const dem = d.demanda;
const midia = d.midia;
const cons = d.consentimento;
const origem = d.origem_lead;

function trim(v) { return (v || '').toString().trim(); }
function lc(v) { return trim(v).toLowerCase(); }
function maskCPF(cpf) {
  const c = trim(cpf).replace(/\D/g, '');
  if (c.length < 11) return '';
  return c.substring(0,3) + '.***.' + c.substring(6,9) + '-' + c.substring(9,11);
}

const protocolo = 'ORC-V2-' + Date.now().toString(36).toUpperCase();

return [{
  json: {
    protocolo,
    nome: trim(lead.nome),
    whatsapp: trim(lead.whatsapp).replace(/\D/g, ''),
    email: lc(lead.email),
    nome_empresa_ou_condominio: trim(lead.nome_empresa_ou_condominio),
    tipo_cliente: lc(lead.tipo_cliente),
    cliente_ativo: lead.cliente_ativo === true || lead.cliente_ativo === 'true',
    cnpj: trim(lead.cnpj).replace(/\D/g, ''),
    cpf_mascarado: maskCPF(lead.cpf),
    responsavel_aprovacao: trim(lead.responsavel_aprovacao),
    cep: trim(loc.cep).replace(/\D/g, ''),
    endereco_completo: trim(loc.endereco_completo),
    bairro: trim(loc.bairro),
    cidade: trim(loc.cidade),
    numero_unidades: infra.numero_unidades || null,
    numero_blocos: infra.numero_blocos || null,
    servico_interesse: trim(dem.servico_interesse),
    urgencia: lc(dem.urgencia),
    melhor_horario: trim(dem.melhor_horario),
    descricao: trim(dem.descricao),
    tipo_orcamento: trim(dem.tipo_orcamento),
    upload_imagem: midia.upload_imagem || [],
    upload_video: midia.upload_video || [],
    aceite_contato: cons.aceite_contato === true,
    aceite_lgpd: cons.aceite_lgpd === true,
    origem: trim(origem.canal),
    versao_form: trim(origem.versao_form),
    pagina_origem: trim(origem.pagina)
  }
}];

// ═══════════════════════════════════════════
// 060 — STEP 3: CLASSIFICAR PENDÊNCIAS
// ═══════════════════════════════════════════

const d = $input.item.json;
const pendencias = [];

// CNPJ
const tiposExigemCNPJ = ['condominio', 'empresa', 'administradora'];
if (tiposExigemCNPJ.includes(d.tipo_cliente) && !d.cnpj) {
  pendencias.push('sem_cnpj');
}

// numero_unidades
if (d.tipo_cliente === 'condominio' && !d.numero_unidades) {
  pendencias.push('sem_numero_unidades');
}

// endereço
if (!d.endereco_completo) {
  pendencias.push('sem_endereco');
}

// descrição
if (!d.descricao) {
  pendencias.push('sem_descricao');
}

// LGPD
if (!d.aceite_lgpd) {
  pendencias.push('sem_lgpd');
}

// Mídia placeholder
const todasMidias = [...(d.upload_imagem || []), ...(d.upload_video || [])];
if (todasMidias.some(u => u.startsWith('pending://'))) {
  pendencias.push('midia_placeholder');
}

// Rateio
let rateio_permitido = false;
if (d.tipo_cliente === 'condominio' && d.numero_unidades && d.numero_unidades > 0) {
  rateio_permitido = true;
}

// Status
const criticas = ['sem_endereco', 'sem_descricao', 'sem_lgpd'];
const temCritica = pendencias.some(p => criticas.includes(p));
const status_orcamento = temCritica ? 'pendente_dados' : 'recebido_para_triagem';

return [{
  json: {
    ...d,
    pendencias,
    rateio_permitido,
    status_orcamento
  }
}];

// ═══════════════════════════════════════════
// 060 — STEP 5: MONTAR MENSAGEM TELEGRAM
// ═══════════════════════════════════════════

const d = $input.item.json;

const pendenciasStr = d.pendencias && d.pendencias.length > 0
  ? JSON.parse(d.pendencias).join(', ')
  : 'nenhuma';

const msg = [
  '🆕 *Novo Lead — Avaliação Técnica V2*',
  '',
  '📋 *Protocolo:* ' + d.protocolo,
  '👤 *Nome:* ' + d.nome,
  '🏢 *Tipo:* ' + d.tipo_cliente,
  '🏠 *Empresa/Condomínio:* ' + d.nome_empresa_ou_condominio,
  '🔧 *Serviço:* ' + d.servico_interesse,
  '⚡ *Urgência:* ' + d.urgencia,
  '📍 *Bairro/Cidade:* ' + d.bairro + ' / ' + d.cidade,
  '',
  '⚠️ *Pendências:* ' + pendenciasStr,
  '📊 *Rateio permitido:* ' + (d.rateio_permitido === true || d.rateio_permitido === 'true' ? 'sim' : 'não'),
  '📌 *Status:* ' + d.status_orcamento,
  '',
  '_Via formulário V2 — ambiente de teste_'
].join('\n');

return [{ json: { ...d, telegram_msg: msg } }];

// ═══════════════════════════════════════════
// 060 — STEP 6: RESPOSTA HTTP PARA O FORMULÁRIO
// ═══════════════════════════════════════════

const d = $input.item.json;

return [{
  json: {
    ok: true,
    status: 'recebido',
    protocolo: d.protocolo,
    status_orcamento: d.status_orcamento,
    pendencias: JSON.parse(d.pendencias || '[]')
  }
}];

// Retorna o erro que abortou o fluxo
const d = $input.item.json;
return [{
  json: {
    ok: false,
    erro: d.erro || 'Erro desconhecido'
  }
}];
